// // This module captures the 16-bit input 'cnt' on the rising edge of the 'signalCapteur' signal and stores it in the 16-bit output 'memo'.
module top_module(cnt,signalCapteur,memo);input signalCapteur;
input [15:0] cnt;
output reg[15:0] memo;

always@(negedge(signalCapteur))
begin
	memo <= cnt;
end
endmodule
